document.addEventListener('DOMContentLoaded', function() {
    var fileInput = document.getElementById('file-input');
    var settingsPanel = document.getElementById('settings-panel');
    var applyBtn = document.getElementById('apply-btn');
    var resetBtn = document.getElementById('reset-btn');
    var fileList = document.getElementById('file-list');
    var progressSection = document.getElementById('progress-section');
    var progressFill = document.getElementById('progress-fill');
    var progressPercent = document.getElementById('progress-percent');
    var progressText = document.getElementById('progress-text');

    var archiveFile = null;
    var processed = false;
    var currentBlob = null;
    var currentFilename = '';

    function showNotification(message, isError) {
        var existing = document.querySelector('.notification');
        if (existing) existing.remove();
        var el = document.createElement('div');
        el.className = 'notification' + (isError ? ' error' : '');
        el.textContent = message;
        document.body.appendChild(el);
        setTimeout(function() { el.remove(); }, 3500);
    }

    function formatSize(bytes) {
        if (bytes < 1024) return bytes + ' B';
        if (bytes < 1048576) return (bytes / 1024).toFixed(1) + ' KB';
        return (bytes / 1048576).toFixed(1) + ' MB';
    }

    function renderFileList() {
        if (!archiveFile) {
            fileList.innerHTML = '';
            applyBtn.disabled = true;
            settingsPanel.classList.remove('show');
            return;
        }
        settingsPanel.classList.add('show');
        applyBtn.disabled = false;
        var html = '<div class="file-item"><span class="file-name">' + archiveFile.name + '</span><span class="file-size">' + formatSize(archiveFile.size) + '</span><button class="remove-btn" id="remove-archive-btn" aria-label="Remove file"><svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M18 6L6 18M6 6l12 12"/></svg></button></div>';
        fileList.innerHTML = html;
        var removeBtn = document.getElementById('remove-archive-btn');
        if (removeBtn) {
            removeBtn.addEventListener('click', function() {
                archiveFile = null;
                renderFileList();
            });
        }
    }

    function showDownloadSection(filename, blob) {
        currentBlob = blob;
        currentFilename = filename;
        var old = document.getElementById('result-section');
        if (old) old.remove();

        var section = document.createElement('div');
        section.id = 'result-section';
        section.style.cssText = 'margin-top:var(--space-4);padding:var(--space-4);background:#f0fdf4;border:1px solid #bbf7d0;border-radius:12px;display:block';
        section.innerHTML =
            '<div style="display:flex;align-items:center;gap:var(--space-3);margin-bottom:var(--space-3)">' +
                '<i class="fas fa-check-circle" style="color:#16a34a;font-size:1.5rem"></i>' +
                '<div><div style="font-weight:600;color:#166534">Extraction Complete!</div>' +
                '<div style="font-size:var(--text-sm);color:var(--color-text-light)">' + filename + ' (' + formatSize(blob.size) + ')</div></div>' +
            '</div>' +
            '<button id="download-btn" class="btn btn-primary btn-lg" style="width:100%"><i class="fas fa-download"></i> Download ' + filename + '</button>';

        settingsPanel.insertBefore(section, settingsPanel.firstChild);

        document.getElementById('download-btn').addEventListener('click', function() {
            var url = URL.createObjectURL(currentBlob);
            var a = document.createElement('a');
            a.href = url;
            a.download = currentFilename;
            document.body.appendChild(a);
            a.click();
            setTimeout(function() { document.body.removeChild(a); URL.revokeObjectURL(url); }, 100);
            showNotification(currentFilename + ' downloaded!');
        });

        applyBtn.style.display = 'none';
        progressSection.style.display = 'none';
        processed = true;
    }

    function showLimitationSection(message) {
        var old = document.getElementById('result-section');
        if (old) old.remove();

        var section = document.createElement('div');
        section.id = 'result-section';
        section.style.cssText = 'margin-top:var(--space-4);padding:var(--space-4);background:#fffbeb;border:1px solid #fde68a;border-radius:12px;display:block';
        section.innerHTML =
            '<div style="display:flex;align-items:center;gap:var(--space-3);margin-bottom:var(--space-3)">' +
                '<i class="fas fa-exclamation-triangle" style="color:#d97706;font-size:1.5rem"></i>' +
                '<div><div style="font-weight:600;color:#92400e">Limitation</div>' +
                '<div style="font-size:var(--text-sm);color:#92400e">' + message + '</div></div>' +
            '</div>' +
            '<div style="padding:var(--space-3);background:#fef3c7;border:1px solid #fde68a;border-radius:8px;font-size:var(--text-sm);color:#92400e">' +
                'Try using 7-Zip or WinRAR on your desktop for full extraction support.' +
            '</div>';

        settingsPanel.insertBefore(section, settingsPanel.firstChild);

        applyBtn.style.display = 'none';
        progressSection.style.display = 'none';
        processed = true;
    }

    function parse7zHeader(data) {
        var sig = [0x37, 0x7A, 0xBC, 0xAF, 0x27, 0x1C];
        for (var i = 0; i < 6; i++) {
            if (data[i] !== sig[i]) return null;
        }
        return {
            version: data[6] | (data[7] << 8),
            startHeaderCrc: (data[8] | (data[9] << 8) | (data[10] << 16) | (data[11] << 24)) >>> 0,
            nextHeaderOffset: (data[12] | (data[13] << 8) | (data[14] << 16) | (data[15] << 24)) >>> 0,
            nextHeaderSize: (data[16] | (data[17] << 8) | (data[18] << 16) | (data[19] << 24)) >>> 0,
            nextHeaderCrc: (data[20] | (data[21] << 8) | (data[22] << 16) | (data[23] << 24)) >>> 0
        };
    }

    function loadPako(callback) {
        if (window.pako) { callback(window.pako); return; }
        var script = document.createElement('script');
        script.src = 'https://cdn.jsdelivr.net/npm/pako@2.1.0/dist/pako.min.js';
        script.onload = function() { callback(window.pako); };
        script.onerror = function() { showNotification('Failed to load decompression library', true); };
        document.head.appendChild(script);
    }

    var dropZone = document.querySelector('.upload-area');
    if (dropZone) {
        dropZone.addEventListener('dragover', function(e) { e.preventDefault(); dropZone.style.borderColor = 'var(--color-primary)'; });
        dropZone.addEventListener('dragleave', function() { dropZone.style.borderColor = ''; });
        dropZone.addEventListener('drop', function(e) {
            e.preventDefault();
            dropZone.style.borderColor = '';
            if (e.dataTransfer.files.length) {
                archiveFile = e.dataTransfer.files[0];
                processed = false;
                var old = document.getElementById('result-section');
                if (old) old.remove();
                renderFileList();
            }
        });
    }

    fileInput.addEventListener('change', function(e) {
        if (e.target.files.length) {
            archiveFile = e.target.files[0];
            processed = false;
            var old = document.getElementById('result-section');
            if (old) old.remove();
            renderFileList();
        }
        fileInput.value = '';
    });

    applyBtn.addEventListener('click', function() {
        if (!archiveFile) return;

        var old = document.getElementById('result-section');
        if (old) old.remove();
        processed = false;

        progressSection.style.display = 'block';
        applyBtn.disabled = true;
        progressText.textContent = 'Reading 7Z header...';
        progressFill.style.width = '20%';
        progressPercent.textContent = '20%';

        loadPako(function(pako) {
            var reader = new FileReader();
            reader.onload = function(ev) {
                try {
                    var data = new Uint8Array(ev.target.result);
                    var header = parse7zHeader(data);

                    if (!header) {
                        showLimitationSection('Not a valid 7Z file. The file signature could not be recognized.');
                        showNotification('Not a valid 7Z file', true);
                        return;
                    }

                    progressFill.style.width = '50%';
                    progressPercent.textContent = '50%';
                    progressText.textContent = 'Attempting decompression...';

                    var nextHeaderStart = 32 + header.nextHeaderOffset;
                    var nextHeaderData = data.slice(nextHeaderStart, nextHeaderStart + header.nextHeaderSize);

                    if (nextHeaderData.length === 0) {
                        showLimitationSection('The 7Z archive appears to be empty or uses an unsupported structure.');
                        showNotification('No extractable data found in 7Z file', true);
                        return;
                    }

                    try {
                        var decompressed = pako.inflate(nextHeaderData);
                        var fileName = archiveFile.name.replace(/\.7z$/i, '') + '_extracted';

                        progressFill.style.width = '80%';
                        progressPercent.textContent = '80%';
                        progressText.textContent = 'Preparing download...';

                        var blob = new Blob([decompressed], { type: 'application/octet-stream' });

                        progressFill.style.width = '100%';
                        progressPercent.textContent = '100%';
                        progressText.textContent = 'Done!';

                        showDownloadSection(fileName, blob);
                        showNotification('Extracted file from 7Z archive!');
                    } catch (e) {
                        showLimitationSection('This 7Z file uses a compression method that requires desktop software. The built-in decompressor could not handle this format.');
                        showNotification('Extraction failed: unsupported compression method', true);
                    }
                } catch (err) {
                    showNotification('Error extracting 7Z: ' + err.message, true);
                    applyBtn.disabled = false;
                    progressSection.style.display = 'none';
                }
            };
            reader.readAsArrayBuffer(archiveFile);
        });
    });

    resetBtn.addEventListener('click', function() {
        archiveFile = null;
        processed = false;
        currentBlob = null;
        var old = document.getElementById('result-section');
        if (old) old.remove();
        renderFileList();
        progressSection.style.display = 'none';
        applyBtn.style.display = '';
        applyBtn.disabled = true;
    });
});
